FROM PERSONAL  P 
INNER JOIN GENEROS G                    ON P.SEXO     = G.CODIGO
INNER JOIN PERIODOS PER                 ON P.COMPANIA = PER.COMPANIA
INNER JOIN CENTRO_COSTO CC              ON P.COMPANIA = CC.COMPANIA     AND P.ID_CENTRO_DE_COSTO = CC.CODIGO  AND CC.ANO = PER.ANO
INNER JOIN AUXILIAR AUX                 ON P.COMPANIA = AUX.COMPANIA    AND P.COD_AUXILIAR = AUX.CODIGO       AND AUX.ANO = PER.ANO
INNER JOIN CARGOS CG                    ON P.COMPANIA = CG.COMPANIA     AND P.ID_DE_CARGO = CG.ID_DE_CARGO 
INNER JOIN ESCALAFON EF                 ON P.COMPANIA = EF.COMPANIA     AND P.ESCALAFON = EF.CODIGO
INNER JOIN CATEGORIA CAT                ON P.COMPANIA = CAT.COMPANIA    AND P.ESCALAFON = CAT.ESCALAFON AND P.ID_DE_CATEGORIA = CAT.ID_DE_CATEGORIA AND P.ANO = CAT.ANO
INNER JOIN TIPOS_DE_EMPLEADO TE         ON P.COMPANIA = TE.COMPANIA     AND P.ID_DE_TIPO = TE.ID_DE_TIPO 
INNER JOIN V_FONDOS FP                  ON P.COMPANIA = FP.COMPANIA     AND P.ID_DEL_FONDO = FP.COD_FONDO
INNER JOIN V_FONDOS FS                  ON P.COMPANIA = FS.COMPANIA     AND P.FONDO_SALUD = FS.COD_FONDO
INNER JOIN V_FONDOS FC                  ON P.COMPANIA = FC.COMPANIA     AND P.FONDO_CESANTIAS = FC.COD_FONDO
INNER JOIN V_FONDOS FR                  ON P.COMPANIA = FR.COMPANIA     AND P.FONDO_RIESGOS = FR.COD_FONDO
INNER JOIN V_FONDOS MP                  ON P.COMPANIA = MP.COMPANIA     AND P.MEDICINA_PREPAGADA = MP.COD_FONDO
INNER JOIN V_FONDOS CCP                 ON P.COMPANIA = CCP.COMPANIA    AND P.CAJA_COMPENSACION = CCP.COD_FONDO
INNER JOIN V_FONDOS FSD                 ON P.COMPANIA = FSD.COMPANIA    AND P.FONDO_SINDICATO = FSD.COD_FONDO
INNER JOIN V_FONDOS FPV                 ON P.COMPANIA = FPV.COMPANIA    AND P.FONDO_PENSION_VOL = FPV.COD_FONDO
INNER JOIN V_FONDOS FAFC                ON P.COMPANIA = FAFC.COMPANIA   AND P.FONDO_AFC = FAFC.COD_FONDO
INNER JOIN BANCO B                      ON P.COMPANIA = B.COMPANIA      AND P.BANCO = B.BANCO
INNER JOIN DEPENDENCIA DP               ON P.COMPANIA = DP.COMPANIA     AND P.DEPENDENCIA =  DP.CODIGO
LEFT JOIN ESTABLECIMIENTOS_DOCENTES ED ON P.COMPANIA = ED.COMPANIA     AND P.CODIGO_ESTABLECIMIENTO = ED.CODIGO
LEFT JOIN FORMANOMBRAMIENTO FN         ON P.COMPANIA = FN.COMPANIA     AND P.DE_CARRERA = FN.IDFORMA
LEFT JOIN PATRONALES PATRO             ON P.COMPANIA = PATRO.COMPANIA  AND P.NUMEROPATRONAL = PATRO.SUCURSAL
INNER JOIN REGIMEN_CESANTIAS RC         ON P.REGIMEN = RC.CODIGO
INNER JOIN ESTADO_ACTUAL EA             ON P.ESTADO_ACTUAL = EA.CODIGO
INNER JOIN TIPO_VINCULACION             ON P.TIPOVINCULACION  = TIPO_VINCULACION.CODIGO
INNER JOIN SUB_TIPOCOTIZANTE            ON P.SUBTIPOCOTIZANTE = SUB_TIPOCOTIZANTE.CODIGO
INNER JOIN SEDES                        ON P.COMPANIA = SEDES.COMPANIA AND P.SEDE     = SEDES.CODIGO
LEFT JOIN CIUDAD CIU_HAB          ON P.PAIS_HAB     = CIU_HAB.PAIS   AND P.DEPARTAMENTO_HAB = CIU_HAB.DEPARTAMENTO     AND P.CIUDAD_HAB = CIU_HAB.CODIGO
LEFT JOIN DEPARTAMENTO DPTO_HAB   ON P.PAIS_HAB     = DPTO_HAB.PAIS  AND P.DEPARTAMENTO_HAB = DPTO_HAB.CODIGO
LEFT JOIN PAISES PS_HAB           ON P.PAIS_HAB     = PS_HAB.PAIS
LEFT JOIN CIUDAD CIU_LAB          ON P.PAIS_LABORA  = CIU_LAB.PAIS   AND P.DEPARTAMENTO_LABORA = CIU_LAB.DEPARTAMENTO  AND P.CIUDAD_HAB = CIU_LAB.CODIGO
LEFT JOIN DEPARTAMENTO DPTO_LAB   ON P.PAIS_LABORA  = DPTO_LAB.PAIS  AND P.DEPARTAMENTO_LABORA = DPTO_LAB.CODIGO
LEFT JOIN PAISES PS_LAB           ON P.PAIS_LABORA  = PS_LAB.PAIS
LEFT JOIN CIUDAD CIU_CEDU         ON P.PAIS_CED     = CIU_CEDU.PAIS  AND P.DEPARTAMENTO_CED = CIU_CEDU.DEPARTAMENTO    AND P.EXPEDIDA = CIU_CEDU.CODIGO
LEFT JOIN DEPARTAMENTO DPTO_CEDU  ON P.PAIS_CED     = DPTO_CEDU.PAIS AND P.DEPARTAMENTO_CED = DPTO_CEDU.CODIGO
LEFT JOIN PAISES PS_CEDU          ON P.PAIS_CED     = PS_CEDU.PAIS
LEFT JOIN CIUDAD CIU_NACI         ON P.PAIS_NAC     = CIU_NACI.PAIS  AND P.DEPARTAMENTO_NAC = CIU_NACI.DEPARTAMENTO    AND P.CIUDAD_NAC = CIU_NACI.CODIGO
LEFT JOIN DEPARTAMENTO DPTO_NACI  ON P.PAIS_NAC     = DPTO_NACI.PAIS AND P.DEPARTAMENTO_NAC = DPTO_NACI.CODIGO
LEFT JOIN PAISES PS_NACI          ON P.PAIS_NAC     = PS_NACI.PAIS
LEFT JOIN TIPO_ACTIVIDAD          ON P.TIPOACTIVIDAD= TIPO_ACTIVIDAD.CODIGO
LEFT JOIN TIPOS_DOCUMENTOS        ON P.COMPANIA     = TIPOS_DOCUMENTOS.COMPANIA  AND P.DCTO_IDENTIDAD=TIPOS_DOCUMENTOS.DCTO_IDENTIDAD
LEFT JOIN CAUSARETIRO             ON P.COMPANIA     = CAUSARETIRO.COMPANIA AND P.CAUSA_RETIRO =CAUSARETIRO.CODIGO
LEFT JOIN ESTADO_CIVIL EC         ON P.COMPANIA     = EC.COMPANIA AND P.ESTADO_CIVIL = EC.ESTADO_CIVIL;

   COMMENT ON COLUMN "V_PERSONAL"."COMPANIA" IS 'Codigo de la compania a la que pertenece el registro';
   COMMENT ON COLUMN "V_PERSONAL"."ID_DE_PROCESO" IS 'Identifica el proceso de calculo de nomina';
   COMMENT ON COLUMN "V_PERSONAL"."ANO" IS 'Ano al que pertenece el registro';
   COMMENT ON COLUMN "V_PERSONAL"."MES" IS 'identificar numerico del mes al cual pertenece el registro';
   COMMENT ON COLUMN "V_PERSONAL"."PERIODO" IS 'Identifica el periodo asociado en el registro';
   COMMENT ON COLUMN "V_PERSONAL"."ID_DE_EMPLEADO" IS 'Identifica el cÃ³digo del empleado';
   COMMENT ON COLUMN "V_PERSONAL"."APELLIDO1" IS 'Identifica el apellido1 del empleado';
   COMMENT ON COLUMN "V_PERSONAL"."APELLIDO2" IS 'Identifica el apellido2 del empleado';
   COMMENT ON COLUMN "V_PERSONAL"."SEXO" IS 'Genero de la persona, empleado o tercero';
   COMMENT ON COLUMN "V_PERSONAL"."NUMERO_DCTO" IS 'Identificacion del empleado o tercero ';
   COMMENT ON COLUMN "V_PERSONAL"."SUCURSAL" IS 'identificar de la sucursal a la cual pertenece el tercero del registro';
   COMMENT ON COLUMN "V_PERSONAL"."FECHA_DE_INGRESO" IS 'Fecha de ingreso de un empleado';
   COMMENT ON COLUMN "V_PERSONAL"."ID_CENTRO_DE_COSTO" IS 'Identificador del centro de costo que se asocia en el registro';
   COMMENT ON COLUMN "V_PERSONAL"."ID_DE_CARGO" IS 'Identificador del cargo que se asocia en el registro';
   COMMENT ON COLUMN "V_PERSONAL"."ID_DE_CATEGORIA" IS 'Identificador de la categoria del empleado que se asocia en el registro';
   COMMENT ON COLUMN "V_PERSONAL"."FECHA_DE_RETIRO" IS 'Fecha de retiro de un empleado';
   COMMENT ON COLUMN "V_PERSONAL"."ID_DEL_FONDO" IS 'Identificador del fondo de pension que se asocia en el registro';
   COMMENT ON COLUMN "V_PERSONAL"."FONDO_SALUD" IS 'Identificador del fondo de salud que se asocia a un empleado';
   COMMENT ON COLUMN "V_PERSONAL"."FONDO_CESANTIAS" IS 'Identificador del fondo de cesantias que se asocia a un empleado';
   COMMENT ON COLUMN "V_PERSONAL"."FONDO_RIESGOS" IS 'Identificador del fondo de riesgos que se asocia a un empleado';
   COMMENT ON COLUMN "V_PERSONAL"."NUMEROPATRONAL" IS 'Identificador del riesgo patronal que se asocia a un empleado';
   COMMENT ON COLUMN "V_PERSONAL"."ESTADO_ACTUAL" IS 'Identifica el estado del empleado';
   COMMENT ON COLUMN "V_PERSONAL"."DEPENDENCIA" IS 'identificar de la dependencia relacionada al registro';
   COMMENT ON COLUMN "V_PERSONAL"."OBSERVACIONES" IS 'Observacion que se le digita al registro';
